sql:
SELECT variant_class
FROM variants
ORDER BY variant_class DESC;

external_knowledge:
- PolyPhen score is a score for predicting the impact of an amino acid substitution on the structure and function of a protein; 
- SIFT score is a score for predicting whether an amino acid substitution affects protein function; 
- Impact severity refers to the severity of the predicted impact of a variant on the function of a gene or protein.

sql:
SELECT gene, variant_type 
FROM variants 
ORDER BY gene;

SELECT variant_id
FROM variants
WHERE variant_id = 1;
